script:
if doc.tipo == "Proforma" and doc.contrato:
    carta = frappe.db.get_value("ContratoVenta", doc.contrato, "carta_reserva")
    if carta:
        precio_original = frappe.db.get_value("CartaReserva", carta, "precio_total")
        if precio_original:
            frappe.db.set_value("ContratoVenta", doc.contrato, "precio_total", precio_original)

if doc.tipo == "Proforma" and doc.contrato:
    carta = frappe.db.get_value("ContratoVenta", doc.contrato, "carta_reserva")
    if carta:
        precio_original = float(frappe.db.get_value("CartaReserva", carta, "precio_total") or 0)
        if precio_original:
            monto_prima = float(frappe.db.get_value("ContratoVenta", doc.contrato, "monto_prima") or 0)
            monto_reserva = float(frappe.db.get_value("ContratoVenta", doc.contrato, "monto_reserva") or 0)
            frappe.db.set_value("ContratoVenta", doc.contrato, "precio_total", precio_original)
            frappe.db.set_value("ContratoVenta", doc.contrato, "monto_financiar", precio_original - monto_prima - monto_reserva)

if doc.proyecto and doc.numero_lote:
    existente = frappe.db.get_value("Lotes", {
        "proyecto": doc.proyecto,
        "numero_lote": doc.numero_lote,
        "name": ["!=", doc.name]
    }, "name")
    if existente:
        frappe.throw(
            "⚠️ El lote <b>{0}</b> ya existe en el proyecto <b>{1}</b>. "
            "Registro existente: {2}".format(doc.numero_lote, doc.proyecto, existente)
        )

if doc.lote:
    existente = frappe.db.get_value("CartaReserva", {
        "lote": doc.lote,
        "estado": "Activa",
        "name": ["!=", doc.name]
    }, "name")
    if existente:
        frappe.throw(
            "El lote " + doc.lote + " ya tiene una Carta de Reserva activa: " +
            existente + ". Cancelala antes de crear una nueva."
        )

if doc.lote:
    existente = frappe.db.get_value("ContratoVenta", {
        "lote": doc.lote,
        "name": ["!=", doc.name]
    }, "name")
    if existente:
        frappe.throw(
            "⚠️ El lote <b>{0}</b> ya tiene un Contrato de Venta: "
            "<b>{1}</b>.".format(doc.lote, existente)
        )

if doc.carta_reserva:
    estado_carta = frappe.db.get_value("CartaReserva", doc.carta_reserva, "estado")
    if estado_carta != "Activa":
        frappe.throw(
            "⚠️ La Carta de Reserva <b>{0}</b> no está Activa "
            "(estado actual: <b>{1}</b>).".format(doc.carta_reserva, estado_carta)
        )

    tiene_contrato = frappe.db.get_value("CartaReserva", doc.carta_reserva, "tiene_contrato")
    if tiene_contrato and doc.name not in [None, ""]:
        existente_cont = frappe.db.get_value("ContratoVenta", {
            "carta_reserva": doc.carta_reserva,
            "name": ["!=", doc.name]
        }, "name")
        if existente_cont:
            frappe.throw(
                "⚠️ La Carta de Reserva <b>{0}</b> ya tiene el contrato "
                "<b>{1}</b> vinculado.".format(doc.carta_reserva, existente_cont)
            )

# ── V8: La tabla de extras no puede estar vacía ───────────────────────────
if not doc.extras:
    frappe.throw(
        "Debe agregar al menos una linea en la tabla de conceptos "
        "antes de guardar el Adendum."
    )

# ── Evitar duplicado por contrato + fecha ─────────────────────────────────
if doc.contrato and doc.fecha:
    existente = frappe.db.get_value("Adendum", {
        "contrato": doc.contrato,
        "fecha": doc.fecha,
        "tipo": doc.tipo,
        "name": ["!=", doc.name]
    }, "name")
    if existente:
        frappe.throw(
            "Ya existe un <b>" + (doc.tipo or "Adendum") + "</b> para el contrato <b>" +
            doc.contrato + "</b> con la misma fecha: <b>" + existente +
            "</b>. Verifique antes de continuar."
        )

# Campos obligatorios
if not doc.proyecto:
    frappe.throw("El campo <b>Proyecto</b> es obligatorio.")

if not doc.bloque:
    frappe.throw("El campo <b>Bloque</b> es obligatorio.")

if not doc.numero_lote:
    frappe.throw("El campo <b>Numero de Lote</b> es obligatorio.")

if not doc.m2_terreno or doc.m2_terreno <= 0:
    frappe.throw("<b>M2 Terreno</b> debe ser mayor a cero.")

# ── V9: Si tiene modelo asignado, m2_casa debe estar definido ─────────────
if doc.catalogo_modelos:
    existe = frappe.db.exists("CatalogoModelos", doc.catalogo_modelos)
    if not existe:
        frappe.throw(
            "El Catalogo de Modelos <b>" + doc.catalogo_modelos +
            "</b> no existe en el sistema."
        )
    if not doc.m2_casa or doc.m2_casa <= 0:
        frappe.throw(
            "El lote tiene el modelo <b>" + doc.catalogo_modelos +
            "</b> asignado pero <b>M2 Casa</b> es cero. "
            "Verifica el catalogo de modelos."
        )

# Duplicado por proyecto + numero_lote
existente = frappe.db.get_value("Lotes", {
    "proyecto": doc.proyecto,
    "numero_lote": doc.numero_lote,
    "name": ["!=", doc.name]
}, "name")
if existente:
    frappe.throw(
        "El lote <b>" + doc.numero_lote + "</b> ya existe en el proyecto "
        "<b>" + doc.proyecto + "</b>. Registro: " + existente
    )

def validar_email(valor):
    if not valor:
        return True
    valor = valor.strip()
    if '@' not in valor:
        return False
    partes = valor.split('@')
    if len(partes) != 2:
        return False
    if not partes[0] or not partes[1]:
        return False
    if '.' not in partes[1]:
        return False
    return True

def validar_telefono(valor):
    if not valor:
        return True
    permitidos = set('0123456789+-. ()')
    for c in valor.strip():
        if c not in permitidos:
            return False
    solo_digitos = ''.join(c for c in valor if c.isdigit())
    return len(solo_digitos) >= 6

def validar_alfanumerico(valor):
    if not valor:
        return True
    permitidos = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789- ')
    for c in valor.strip():
        if c not in permitidos:
            return False
    return True

# ── V3: Bloquear cancelacion si ya tiene contrato ─────────────────────────
if doc.estado == "Cancelada" and doc.tiene_contrato:
    contrato = frappe.db.get_value("ContratoVenta", {"carta_reserva": doc.name}, "name")
    if contrato:
        frappe.throw(
            "No se puede cancelar esta Carta de Reserva porque ya tiene el "
            "Contrato de Venta <b>" + contrato + "</b> vinculado. "
            "Elimine el contrato primero."
        )

# ── Campos obligatorios ────────────────────────────────────────────────────
if not doc.lote:
    frappe.throw("El campo Lote es obligatorio.")

if not doc.fecha:
    frappe.throw("El campo Fecha es obligatorio.")

if not doc.ciudad:
    frappe.throw("El campo Ciudad es obligatorio.")

if not doc.nombre_solicitante:
    frappe.throw("El campo Nombre Solicitante es obligatorio.")

if not doc.numero_identificacion:
    frappe.throw("El campo Numero de Identificacion es obligatorio.")

if not doc.comprobante_de_pago:
    frappe.throw("Debe adjuntar el Comprobante de Pago antes de guardar.")

if not doc.numero_referencia:
    frappe.throw("El campo Numero de Referencia es obligatorio.")

# ── V1: Validar que el lote tenga modelo si es tipo Con Modelo ─────────────
if doc.lote:
    tipo_lote = frappe.db.get_value("Lotes", doc.lote, "tipo_lote")
    catalogo = frappe.db.get_value("Lotes", doc.lote, "catalogo_modelos")
    if tipo_lote == "Con Modelo" and not catalogo:
        frappe.throw(
            "El lote <b>" + doc.lote + "</b> es de tipo <b>Con Modelo</b> pero no "
            "tiene un Catalogo de Modelos asignado. Completa el lote antes de reservarlo."
        )

# ── Validaciones numéricas ─────────────────────────────────────────────────
precio_total = float(doc.precio_total or 0)
monto_reservacion = float(doc.monto_reservacion or 0)

if precio_total <= 0:
    frappe.throw("El Precio Total debe ser mayor a cero.")



# ── V2: monto_reservacion debe ser mayor a cero ───────────────────────────
if monto_reservacion <= 0:
    frappe.throw("El Monto de Reservacion debe ser mayor a cero.")


# ── Validaciones de formato ────────────────────────────────────────────────
errores = []

if not validar_telefono(doc.telefono):
    errores.append("Telefono: solo se permiten numeros, +, - y espacios")

if not validar_telefono(doc.telefono_trabajo):
    errores.append("Telefono Trabajo: solo se permiten numeros, +, - y espacios")

if not validar_telefono(doc.telefono_conyuge):
    errores.append("Telefono Conyuge: solo se permiten numeros, +, - y espacios")

if not validar_telefono(doc.telefono_trabajo_conyuge):
    errores.append("Telefono Trabajo Conyuge: solo se permiten numeros, +, - y espacios")

if not validar_email(doc.correo):
    errores.append("Correo: debe contener @ y un dominio valido")

if not validar_email(doc.correo_conyuge):
    errores.append("Correo Conyuge: debe contener @ y un dominio valido")

if not validar_alfanumerico(doc.numero_identificacion):
    errores.append("Numero Identificacion: solo se permiten letras, numeros y guiones")

if not validar_alfanumerico(doc.numero_id_conyuge):
    errores.append("Numero ID Conyuge: solo se permiten letras, numeros y guiones")

if doc.salario is not None and float(doc.salario or 0) < 0:
    errores.append("Salario: no puede ser negativo")

if doc.salario_conyuge is not None and float(doc.salario_conyuge or 0) < 0:
    errores.append("Salario Conyuge: no puede ser negativo")

if errores:
    mensaje = "Corrige los siguientes errores antes de guardar:\n\n"
    for e in errores:
        mensaje = mensaje + "- " + e + "\n"
    frappe.throw(mensaje)

# ── Escribir vendedor en el Lote ───────────────────────────────────────────
if doc.lote and doc.vendedor:
    frappe.db.set_value("Lotes", doc.lote, "vendedor_asignado", doc.vendedor)

# ── Campos obligatorios ────────────────────────────────────────────────────
if not doc.fecha:
    frappe.throw("Debe ingresar la Fecha.")

if not doc.carta_reserva:
    frappe.throw("Debe seleccionar la Carta de Reserva.")

if not doc.lote:
    frappe.throw("Debe seleccionar el Lote.")

# ── V4: plazo_entrega debe ser mayor a cero ───────────────────────────────
if not doc.plazo_entrega or int(doc.plazo_entrega) <= 0:
    frappe.throw("El Plazo de Entrega debe ser un numero positivo de meses.")

# ── V5: Verificar que la fecha estimada de entrega sea coherente ──────────
if doc.fecha and doc.plazo_entrega:
    fecha_entrega = frappe.utils.getdate(frappe.utils.add_months(doc.fecha, int(doc.plazo_entrega)))
    fecha_hoy = frappe.utils.getdate(frappe.utils.today())
    if fecha_entrega < fecha_hoy:
        frappe.throw(
            "La Fecha Estimada de Entrega calculada (<b>" +
            str(fecha_entrega) + "</b>) ya paso. "
            "Revisa la Fecha del contrato o el Plazo de Entrega."
        )

# ── Validar carta de reserva ───────────────────────────────────────────────
estado_carta = frappe.db.get_value("CartaReserva", doc.carta_reserva, "estado")
if estado_carta != "Activa":
    frappe.throw("La Carta de Reserva <b>" + doc.carta_reserva + "</b> no esta Activa.")

tiene_contrato = frappe.db.get_value("CartaReserva", doc.carta_reserva, "tiene_contrato")
if tiene_contrato:
    contrato_existente = frappe.db.get_value("ContratoVenta", {
        "carta_reserva": doc.carta_reserva,
        "name": ["!=", doc.name]
    }, "name")
    if contrato_existente:
        frappe.throw(
            "La Carta de Reserva <b>" + doc.carta_reserva +
            "</b> ya tiene el contrato <b>" + contrato_existente + "</b> asignado."
        )

# ── Validar no duplicar contrato por lote ─────────────────────────────────
if doc.lote:
    contrato_lote = frappe.db.get_value("ContratoVenta", {
        "lote": doc.lote,
        "name": ["!=", doc.name]
    }, "name")
    if contrato_lote:
        frappe.throw(
            "El lote <b>" + doc.lote +
            "</b> ya tiene el contrato <b>" + contrato_lote + "</b> asignado."
        )

# ── Validar desembolsos ────────────────────────────────────────────────────
if not doc.desembolsos:
    frappe.throw("Debe tener al menos un desembolso registrado.")

total = 0
for d in doc.desembolsos:
    total += float(d.porcentaje or 0)
total = round(total, 2)
if total != 100:
    frappe.throw(
        "Los porcentajes de desembolso suman <b>" + str(total) +
        "%</b>. Deben sumar exactamente 100%."
    )

# ── Marcar carta de reserva como con contrato ─────────────────────────────
if doc.carta_reserva:
    frappe.db.set_value("CartaReserva", doc.carta_reserva, "tiene_contrato", 1)

# ── V7: Al menos una actividad ────────────────────────────────────────────
if not doc.actividades:
    frappe.throw("Debe agregar al menos una actividad antes de guardar.")


# ── V6: Si tipo=Contrato, verificar que el contrato pertenezca al lote ────
if doc.tipo_seguimiento == "Contrato":
    if not doc.contrato:
        frappe.throw(
            "El campo <b>Contrato de Venta</b> es obligatorio cuando el "
            "Tipo de Seguimiento es <b>Contrato</b>."
        )
    else:
        lote_del_contrato = frappe.db.get_value("ContratoVenta", doc.contrato, "lote")
        if lote_del_contrato and lote_del_contrato != doc.lote:
            frappe.throw(
                "El Contrato <b>" + doc.contrato + "</b> pertenece al lote "
                "<b>" + lote_del_contrato + "</b>, no al lote <b>" +
                doc.lote + "</b>. Verifica la seleccion."
            )

if doc.carta_reserva:
    frappe.db.set_value("CartaReserva", doc.carta_reserva, "tiene_contrato", 0)

# R2: Volver lote a Reservado al eliminar contrato
if doc.lote:
    frappe.db.set_value("Lotes", doc.lote, "estado", "Reservado")

if doc.carta_reserva:
    frappe.db.set_value("CartaReserva", doc.carta_reserva, "tiene_contrato", 1)

# R1: Marcar lote como Vendido al crear/guardar contrato
if doc.lote:
    frappe.db.set_value("Lotes", doc.lote, "estado", "Vendido")

# Auto-asignar vendedor al usuario actual si no viene ya asignado
if not doc.vendedor:
    doc.vendedor = frappe.session.user

# Detectar si el lote cambió
old_doc = doc.get_doc_before_save()
old_lote = old_doc.lote if old_doc else None

# Si el lote anterior cambió, liberarlo
if old_lote and old_lote != doc.lote:
    frappe.db.set_value("Lotes", old_lote, "estado", "Disponible")

# Actualizar estado del lote actual
if doc.lote:
    if doc.estado == "Cancelada":
        frappe.db.set_value("Lotes", doc.lote, "estado", "Disponible")
    else:
        frappe.db.set_value("Lotes", doc.lote, "estado", "Reservado")
    # Propagar vendedor
    if doc.vendedor:
        frappe.db.set_value("Lotes", doc.lote, "vendedor_asignado", doc.vendedor)
